; 鉱山

name = 鉱山Ｂ５
insideName = Ｂ５
upper = 鉱山Ｂ４
lower = 鉱山Ｂ６
level = 44
bgm = anxiety
roof = stone
shadow = dark
sky = black
outfield = soil
blank = rock

; パーツ画像
━ = soil
　 = soil
／ = door
︻ = mineral
┯ = button
㊤ = ladderu
㊦ = ladderd
④ = zodiac

; 敵情報
maxGroups = 2
monsters = デーモンインプ,シャドウインプ

; 宝箱
box[1] = 聖なるハンドベル_u,パワーヒールの魔法書_u,シルバーリング_u,女の秘薬_u,経験のコイン（小）,精力剤

[map]
